import React, { useState } from 'react';
import { motion } from 'framer-motion';
import axios from 'axios';

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    setPreview(URL.createObjectURL(file));
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('mode', 'segmentation');

    try {
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Check if Flask is running on port 5000");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', backgroundColor: '#F5F7FA', minHeight: '100vh' }}>
      <h1 style={{ color: '#1E88E5' }}>AI Diagnostic Hub</h1>
      
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '30px' }}>
        {/* Comparison Viewer */}
        <div style={{ background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
          <input type="file" onChange={handleUpload} style={{ marginBottom: '20px' }} />
          
          <div style={{ position: 'relative', width: '100%', height: '400px', backgroundColor: '#000', borderRadius: '15px', overflow: 'hidden' }}>
            {preview && <img src={preview} style={{ width: '100%', height: '100%', objectFit: 'contain' }} alt="MRI" />}
            
            {/* Green Lining Overlay */}
            {data?.mask && (
              <motion.img 
                initial={{ opacity: 0 }} 
                animate={{ opacity: 0.6 }} 
                src={data.mask} 
                style={{ 
                    position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', 
                    objectFit: 'contain', filter: 'hue-rotate(90deg) saturate(10) brightness(1.2)' 
                }} 
              />
            )}
            
            {loading && <div style={{ position: 'absolute', top: '50%', left: '40%', color: 'white' }}>AI ANALYZING...</div>}
          </div>
        </div>

        {/* Confidence Gauge */}
        <div style={{ background: '#1E88E5', color: 'white', padding: '30px', borderRadius: '20px' }}>
          <h3>Confidence Level</h3>
          <h2 style={{ fontSize: '3rem' }}>{data ? (data.confidence * 100).toFixed(1) : '00.0'}%</h2>
          <div style={{ height: '10px', background: 'rgba(255,255,255,0.3)', borderRadius: '5px', marginTop: '20px' }}>
            <motion.div 
              initial={{ width: 0 }} 
              animate={{ width: data ? `${data.confidence * 100}%` : 0 }} 
              style={{ height: '100%', background: 'white', borderRadius: '5px' }} 
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
